  2→import type { PolicyRecord, PolicyRule, PolicySelector, PolicyStatus } from "./types";
  3→
  4→// --- Detail Response Types ---
  5→
  6→export type PolicyEdgeInfo = {
  7→  governing: Array<{ identity_id: string; created_at: string }>;
  8→  protects: Array<{ workspace_id: string; created_at: string }>;
  9→};
 10→
 11→export type PolicyVersionChainItem = {
 12→  id: string;
 13→  version: number;
 14→  status: string;
 15→  created_at: string;
 16→};
 17→
 18→// --- List Response Types ---
 19→
 20→export type PolicyListItem = {
 21→  id: string;
 22→  title: string;
 23→  status: string;
 24→  version: number;
 25→  rules_count: number;
 26→  human_veto_required: boolean;
 27→  created_at: string;
 28→  updated_at?: string;
 29→};
 30→
 31→// --- Pure Mapping ---
 32→
 33→const formatTimestamp = (value: Date | string): string =>
 34→  value instanceof Date ? value.toISOString() : String(value);
 35→
 36→const toPolicyListItem = (record: PolicyRecord): PolicyListItem => ({
 37→  id: record.id.id as string,
 38→  title: record.title,
 39→  status: record.status,
 40→  version: record.version,
 41→  rules_count: record.rules?.length ?? 0,
 42→  human_veto_required: record.human_veto_required ?? false,
 43→  created_at: formatTimestamp(record.created_at),
 44→  ...(record.updated_at ? { updated_at: formatTimestamp(record.updated_at) } : {}),
 45→});
