 64→export async function loadActivePolicies(
 65→  surreal: Surreal,
 66→  identityId: RecordId<"identity">,
 67→  workspaceId: RecordId<"workspace">,
 68→): Promise<PolicyRecord[]> {
 69→  const identityResult = await surreal.query<
 70→    [Array<{ policies: PolicyRecord[] }>]
 71→  >(
 72→    `SELECT ->governing->policy.* AS policies FROM $identity;`,
 73→    { identity: identityId },
 74→  );
 75→
 76→  const workspaceResult = await surreal.query<
 77→    [Array<{ policies: PolicyRecord[] }>]
 78→  >(
 79→    `SELECT <-protects<-policy.* AS policies FROM $workspace;`,
 80→    { workspace: workspaceId },
 81→  );
 82→
 83→  const identityPolicies = identityResult[0]?.[0]?.policies ?? [];
 84→  const workspacePolicies = workspaceResult[0]?.[0]?.policies ?? [];
 85→
 86→  // Deduplicate by policy ID and filter active only
 87→  const seen = new Set<string>();
 88→  const result: PolicyRecord[] = [];
 89→  for (const policy of [...identityPolicies, ...workspacePolicies]) {
 90→    const id = policy.id.id as string;
 91→    if (!seen.has(id) && policy.status === "active") {
 92→      seen.add(id);
 93→      result.push(policy);
 94→    }
 95→  }
 96→  return result;
 97→}
