 99→export async function listWorkspacePolicies(
100→  surreal: Surreal,
101→  workspace: RecordId<"workspace">,
102→  statusFilter?: PolicyStatus,
103→): Promise<PolicyListItem[]> {
104→  const query = statusFilter
105→    ? "SELECT * FROM policy WHERE workspace = $ws AND status = $status ORDER BY created_at DESC;"
106→    : "SELECT * FROM policy WHERE workspace = $ws ORDER BY created_at DESC;";
107→
108→  const params: Record<string, unknown> = { ws: workspace };
109→  if (statusFilter) params.status = statusFilter;
110→
111→  const [rows] = await surreal.query<[PolicyRecord[]]>(query, params);
112→
113→  return (rows ?? []).map(toPolicyListItem);
114→}
