146→export async function activatePolicy(
147→  surreal: Surreal,
148→  policy: PolicyRecord,
149→  creatorId: RecordId<"identity">,
150→  workspaceId: RecordId<"workspace">,
151→): Promise<void> {
152→  const policyRecord = policy.id;
153→  const supersededRecord = policy.supersedes;
154→
155→  if (supersededRecord) {
156→    // D5: Validate version chain monotonicity — single query to get old version number
157→    const [oldVersionRows] = await surreal.query<[Array<{ version: number }>]>(
158→      "SELECT version FROM $ref;",
159→      { ref: supersededRecord },
160→    );
161→    const oldVersion = oldVersionRows?.[0]?.version;
162→    if (oldVersion !== undefined && policy.version <= oldVersion) {
163→      throw new Error(
164→        `version ${policy.version} must be greater than superseded version ${oldVersion}`,
165→      );
166→    }
167→
168→    await surreal.query(
169→      `
170→      BEGIN TRANSACTION;
171→        UPDATE $policy SET status = 'active', updated_at = time::now();
172→        RELATE $creator->governing->$policy SET created_at = time::now();
173→        RELATE $policy->protects->$workspace SET created_at = time::now();
174→        UPDATE $oldPolicy SET status = 'superseded', updated_at = time::now();
175→        DELETE governing WHERE out = $oldPolicy;
176→        DELETE protects WHERE in = $oldPolicy;
177→      COMMIT TRANSACTION;
178→    `,
179→      {
180→        policy: policyRecord,
181→        creator: creatorId,
182→        workspace: workspaceId,
183→        oldPolicy: supersededRecord,
184→      },
185→    );
186→  } else {
187→    await surreal.query(
188→      `
189→      BEGIN TRANSACTION;
190→        UPDATE $policy SET status = 'active', updated_at = time::now();
191→        RELATE $creator->governing->$policy SET created_at = time::now();
192→        RELATE $policy->protects->$workspace SET created_at = time::now();
193→      COMMIT TRANSACTION;
194→    `,
195→      {
196→        policy: policyRecord,
197→        creator: creatorId,
198→        workspace: workspaceId,
199→      },
200→    );
201→  }
202→}
