271→export function buildVersionChainSingle(policy: PolicyRecord): PolicyVersionChainItem[] {
272→  return [{
273→    id: policy.id.id as string,
274→    version: policy.version,
275→    status: policy.status,
276→    created_at: formatTimestamp(policy.created_at),
277→  }];
278→}
279→
280→// ---------------------------------------------------------------------------
281→// Version chain resolution — single-query bulk fetch + in-memory traversal
282→// ---------------------------------------------------------------------------
283→
284→/**
285→ * Fetch all versioned policies in the workspace in one query, then walk the
286→ * supersedes chain in memory. Replaces N sequential DB round-trips with 1.
287→ */
288→async function resolveChainFromPool(
289→  surreal: Surreal,
290→  policy: PolicyRecord,
291→): Promise<PolicyRecord[]> {
292→  // Single round-trip: fetch all workspace policies that participate in any
293→  // supersedes relationship (as source or target). The LET subquery collects
294→  // IDs referenced as supersedes targets so root policies (which lack
295→  // supersedes themselves) are included in the pool.
296→  const [, pool] = await surreal.query<[unknown, PolicyRecord[]]>(
297→    `LET $targets = SELECT VALUE supersedes FROM policy WHERE workspace = $ws AND supersedes != NONE;
298→     SELECT * FROM policy WHERE workspace = $ws AND (
299→       supersedes != NONE OR id IN $targets OR id = $id
300→     ) ORDER BY version ASC;`,
301→    { ws: policy.workspace, id: policy.id },
302→  );
303→
304→  // Build lookup maps for in-memory traversal
305→  const byId = new Map<string, PolicyRecord>();
306→  const bySupersedes = new Map<string, PolicyRecord>(); // key = superseded policy id
307→  for (const p of pool) {
308→    byId.set(p.id.id as string, p);
309→    if (p.supersedes) {
310→      bySupersedes.set(p.supersedes.id as string, p);
311→    }
312→  }
313→
314→  // Ensure the starting policy is in the pool (it may lack supersedes)
315→  if (!byId.has(policy.id.id as string)) {
316→    byId.set(policy.id.id as string, policy);
317→  }
318→
319→  // Walk backward to root
320→  const chain: PolicyRecord[] = [];
321→  const seen = new Set<string>();
322→  let current: PolicyRecord | undefined = policy;
323→  const ancestors: PolicyRecord[] = [];
324→  while (current?.supersedes) {
325→    const parentId = current.supersedes.id as string;
326→    if (seen.has(parentId)) break;
327→    seen.add(parentId);
328→    const parent = byId.get(parentId);
329→    if (!parent) break;
330→    ancestors.unshift(parent);
331→    current = parent;
332→  }
333→
334→  chain.push(...ancestors);
335→  if (!seen.has(policy.id.id as string)) {
336→    seen.add(policy.id.id as string);
337→    chain.push(policy);
338→  }
339→
340→  // Walk forward to latest
341→  let latestId = policy.id.id as string;
342→  for (let i = 0; i < 50; i++) {
343→    const child = bySupersedes.get(latestId);
344→    if (!child) break;
345→    const childId = child.id.id as string;
346→    if (seen.has(childId)) break;
347→    seen.add(childId);
348→    chain.push(child);
349→    latestId = childId;
350→  }
351→
352→  chain.sort((a, b) => a.version - b.version);
353→  return chain;
354→}
355→
356→/** Build version chain formatted as PolicyVersionChainItem[]. */
357→export async function buildVersionChain(
358→  surreal: Surreal,
359→  policy: PolicyRecord,
360→): Promise<PolicyVersionChainItem[]> {
361→  const chain = await resolveChainFromPool(surreal, policy);
362→  return chain.map((v) => ({
363→    id: v.id.id as string,
364→    version: v.version,
365→    status: v.status,
366→    created_at: formatTimestamp(v.created_at),
367→  }));
368→}
369→
370→/** Build enriched version chain (includes title + rules_count). */
371→export async function getVersionChain(
372→  surreal: Surreal,
373→  policyId: string,
374→  workspace: RecordId<"workspace">,
375→): Promise<Array<PolicyVersionChainItem & { title: string; rules_count: number }> | undefined> {
376→  const policy = await getPolicyById(surreal, policyId, workspace);
377→  if (!policy) return undefined;
378→
379→  const chain = await resolveChainFromPool(surreal, policy);
380→  return chain.map((v) => ({
381→    id: v.id.id as string,
382→    version: v.version,
383→    status: v.status,
384→    created_at: formatTimestamp(v.created_at),
385→    title: v.title,
386→    rules_count: v.rules?.length ?? 0,
387→  }));
388→}
389→
390→export async function createPolicyAuditEvent(
391→  surreal: Surreal,
392→  eventType: string,
393→  actor: RecordId<"identity">,
394→  workspace: RecordId<"workspace">,
395→  policyId: string,
396→  version: number,
397→): Promise<void> {
398→  const auditId = `audit-${crypto.randomUUID()}`;
399→  const auditRecord = new RecordId("audit_event", auditId);
400→
401→  await surreal.query("CREATE $audit CONTENT $content;", {
402→    audit: auditRecord,
403→    content: {
404→      event_type: eventType,
405→      actor,
406→      workspace,
407→      payload: {
408→        policy_id: policyId,
409→        policy_version: version,
410→      },
411→      severity: "info",
412→      created_at: new Date(),
413→    },
414→  });
